final:
module RefModule(
   input                clk,
   input                rst_n,
   input                load,
   input  [7:0]         D,

   output reg [7:0]     Q
);
      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always@(posedge clk or negedge rst_n or posedge dbg_halt)begin
        if(!rst_n) Q <= 8'd0;
        else if(load) Q <= D;
        else Q <= Q << 1;
    end
endmodule
